import React, { useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { formatRent, safeFloat } from '../../../utils/formatters';

const OwnershipSection = ({ units = [], leases = [], loading }) => {
  const navigate = useNavigate();

  const ownershipData = useMemo(() => {
    // The 3 displayed ownership categories (Unsold is tracked internally but not shown)
    const displayCategories = [
      { key: 'Developer Units', label: 'Developer Units', color: '#e8a830' },
      { key: 'Close Group', label: 'Close Group', color: '#2d8a4e' },
      { key: 'External Investors', label: 'External Investors', color: '#1e3a5f' },
    ];

    // All 4 buckets (including Unsold for internal tracking)
    const grouped = {
      'Unsold': { units: 0, totalArea: 0, totalRent: 0, parties: new Set() },
      'Developer Units': { units: 0, totalArea: 0, totalRent: 0, parties: new Set() },
      'Close Group': { units: 0, totalArea: 0, totalRent: 0, parties: new Set() },
      'External Investors': { units: 0, totalArea: 0, totalRent: 0, parties: new Set() },
    };

    console.log('[OwnershipSection] units count:', units?.length, 'leases count:', leases?.length);

    if (!units || units.length === 0) {
      return displayCategories.map(cat => ({
        key: cat.key, label: cat.label, color: cat.color,
        units: 0, totalArea: 0, totalRent: 0, parties: 0,
      }));
    }

    // Build lease → rent map for active leases
    const leaseRentMap = {};
    (leases || []).forEach(lease => {
      const s = (lease.status || '').toLowerCase().trim();
      const isActive = s === 'active' || s === 'approved' || s === 'executed' || s === 'registered' || s === 'occupied';
      if (isActive) {
        const unitId = lease.unit_id || lease.unitId || lease.unit?.id;
        const rent = parseFloat(lease.monthly_rent) || 0;
        if (unitId && rent > 0) leaseRentMap[unitId] = rent;
      }
    });

    // Group each unit by its ownership_grouping (set by backend)
    units.forEach(unit => {
      const grouping = unit.ownership_grouping || 'Unsold';
      const bucket = grouped[grouping] ?? grouped['Unsold'];

      console.log(`[OwnershipSection] unit ${unit.id} (${unit.unit_number}) → ownership_grouping: "${grouping}", owner_name: "${unit.owner_name}"`);

      bucket.units += 1;
      bucket.totalArea += parseFloat(unit.chargeable_area || 0);
      bucket.totalRent += leaseRentMap[unit.id] || 0;

      if (unit.owner_name && unit.owner_name !== 'N/A') {
        bucket.parties.add(unit.owner_name);
      }
    });

    // Return only the 3 display categories (exclude Unsold row)
    return displayCategories.map(cat => ({
      key: cat.key,
      label: cat.label,
      color: cat.color,
      units: grouped[cat.key].units,
      totalArea: grouped[cat.key].totalArea,
      totalRent: grouped[cat.key].totalRent,
      parties: grouped[cat.key].parties.size,
    }));
  }, [units, leases]);

  const handleCategoryClick = (category) => {
    navigate(`/admin/units?ownership=${encodeURIComponent(category)}`);
  };

  // Total only across the 3 displayed categories
  const totalOwned = ownershipData.reduce((sum, o) => sum + o.units, 0);

  const displayData = ownershipData.map(o => ({
    ...o,
    percentage: totalOwned > 0 ? parseFloat(((o.units / totalOwned) * 100).toFixed(1)) : 0,
    avgRent: o.totalArea > 0 ? parseFloat((o.totalRent / o.totalArea).toFixed(2)) : 0,
  }));

  const formatArea = (area) => {
    if (area >= 100000) return `${(area / 100000).toFixed(1)}L sqft`;
    return `${area.toLocaleString('en-IN')} sqft`;
  };

  return (
    <div className="echo-card" style={{ border: 'none' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a', marginBottom: '2px' }}>Unit Sales & Ownership</h3>
      <p style={{ fontSize: '12px', color: '#64748b', marginBottom: '16px' }}>{totalOwned} assigned units · by ownership category</p>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>Loading...</div>
      ) : (
        <>
          <style>{`
            .ownership-scroll-container::-webkit-scrollbar { width: 6px; }
            .ownership-scroll-container::-webkit-scrollbar-track { background: #f1f5f9; border-radius: 3px; }
            .ownership-scroll-container::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 3px; }
            .ownership-scroll-container::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
          `}</style>

          {/* Stacked bar — only shows if there are owned units */}
          {totalOwned > 0 && (
            <>
              <div style={{ display: 'flex', height: '16px', borderRadius: '4px', overflow: 'hidden', marginBottom: '8px' }}>
                {displayData.map((o, i) => (
                  <div key={i} style={{ backgroundColor: o.color, width: `${o.percentage}%` }} />
                ))}
              </div>
              <div style={{ display: 'flex', gap: '16px', fontSize: '10px', color: '#64748b', marginBottom: '24px', flexWrap: 'wrap' }}>
                {displayData.map((o, i) => (
                  <span key={i} style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <span style={{ width: '8px', height: '8px', borderRadius: '2px', display: 'inline-block', backgroundColor: o.color }} />
                    {o.label.split(' ')[0]} ({o.percentage}%)
                  </span>
                ))}
              </div>
            </>
          )}

          {/* Breakdown rows — always show all 3 categories */}
          <div
            className="ownership-scroll-container"
            style={{ display: 'flex', flexDirection: 'column', gap: '20px', maxHeight: '220px', overflowY: 'auto', paddingRight: '8px' }}
          >
            {displayData.map((o, i) => (
              <div
                key={i}
                onClick={() => handleCategoryClick(o.key)}
                style={{ display: 'flex', alignItems: 'flex-start', gap: '12px', cursor: 'pointer', padding: '4px', borderRadius: '4px', transition: 'background-color 0.2s' }}
                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f8fafc'}
                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
              >
                <span style={{ width: '12px', height: '12px', borderRadius: '2px', marginTop: '2px', flexShrink: 0, backgroundColor: o.color }} />
                <div style={{ flex: 1 }}>
                  <p style={{ fontSize: '14px', fontWeight: 500, color: '#0f172a', margin: 0 }}>{o.label}</p>
                  <p style={{ fontSize: '12px', color: '#64748b', margin: 0 }}>
                    {o.units} unit{o.units !== 1 ? 's' : ''} · {formatArea(o.totalArea)}
                    {o.parties > 0 ? ` · ${o.parties} ${o.parties === 1 ? 'party' : 'parties'}` : ''}
                  </p>
                </div>
                <div style={{ textAlign: 'right', flexShrink: 0 }}>
                  <p style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a', margin: 0 }}>{formatRent(safeFloat(o.totalRent))} PM</p>
                  <p style={{ fontSize: '12px', color: '#64748b', margin: 0 }}>Rs {o.avgRent}/sqft avg</p>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

export default OwnershipSection;
